import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, X, Loader2, ImageIcon, Sparkles, Database, Calendar, Trash, ArrowLeft, Tag
} from 'lucide-react';

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  // Estado inicial respetando el Schema de Oferta
  const filaNueva = () => ({
    id: Date.now() + Math.random(),
    producto: '',
    precioNuevo: '',
    precioViejo: '', // Requerido por el modelo
    stock: '',
    peso: 0,
    limitePorCliente: 3,
    categoria: 'Almacén',
    publicado: true,
    fotoSugerida: null
  });

  const [filas, setFilas] = useState([filaNueva()]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [showGaleria, setShowGaleria] = useState(false);
  const [cargando, setCargando] = useState(false);

  const API_URL = "http://localhost:5000"; 
  const CLOUD_NAME = "dwpgncjgn";

  useEffect(() => {
    axios.get(`${API_URL}/api/galeria`).then(res => setGaleria(res.data)).catch(e => console.log(e));
  }, [showGaleria]);

  const buscarMatch = (texto) => {
    if (!texto || texto.length < 3) return null;
    const t = texto.toLowerCase();
    const palabras = t.split(' ').filter(p => p.length > 1);
    return galeria.find(f => palabras.every(p => f.nombreReferencia.includes(p)));
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split('\n').filter(line => line.trim() !== '');
    
    const nuevasFilas = lineas.map(line => {
      const celdas = line.split('\t');
      const nombre = celdas[0] || '';
      const precio = celdas[1] || '';
      return {
        ...filaNueva(),
        id: Math.random(),
        producto: nombre,
        precioNuevo: precio,
        precioViejo: precio, // Por defecto igual al nuevo si se pega de excel
        stock: celdas[2] || 0,
        fotoSugerida: buscarMatch(nombre)
      };
    });
    setFilas(nuevasFilas);
  };

  const actualizarFila = (id, campo, valor) => {
    setFilas(filas.map(f => {
      if (f.id === id) {
        const n = { ...f, [campo]: valor };
        if (campo === 'producto') n.fotoSugerida = buscarMatch(valor);
        return n;
      }
      return f;
    }));
  };

  const publicarOfertas = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Define el rango de fechas de la oferta");
    setCargando(true);
    try {
      const promesas = filas.map(f => {
        if (!f.producto || !f.precioNuevo) return null;
        // Objeto exacto segun tu Schema de Mongoose
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.producto,
          precioNuevo: Number(f.precioNuevo),
          precioViejo: Number(f.precioViejo || f.precioNuevo),
          stock: Number(f.stock),
          peso: Number(f.peso),
          limitePorCliente: Number(f.limitePorCliente),
          publicId: f.fotoSugerida ? f.fotoSugerida.publicId : 'placeholder_id',
          local: localId,
          categoria: f.categoria,
          publicado: true,
          fechaInicioOferta: fechas.inicio,
          fechaFinOferta: fechas.fin
        });
      });
      await Promise.all(promesas.filter(p => p !== null));
      alert("¡Ofertas sincronizadas con éxito!");
      setFilas([filaNueva()]);
    } catch (e) { 
      alert("Error al guardar. Revisa que todos los campos obligatorios estén completos."); 
    } finally { setCargando(false); }
  };

  return (
    <div style={containerStyle}>
      {/* Header con estilo Dashboard */}
      <div style={topNav}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <button onClick={() => setShowGaleria(true)} style={btnOfertaStyle}>
          <Database size={16}/> Biblioteca Maestra
        </button>
      </div>

      <div style={headerSection}>
        <h1 style={sidebarTitle}><Tag color="#e67e22"/> Editor de Inventario</h1>
        <p style={{color: '#94a3b8'}}>Pega tus columnas de Excel (Producto | Precio | Stock) o carga manualmente.</p>
      </div>

      {/* Tabla Estilo Excel con estética Card */}
      <div style={tableWrapper} onPaste={handlePaste}>
        <table style={mainTable}>
          <thead>
            <tr style={thRow}>
              <th style={thCell}>Foto</th>
              <th style={thCell}>Producto / Descripción</th>
              <th style={thCell}>Precio Nuevo</th>
              <th style={thCell}>Precio Viejo</th>
              <th style={thCell}>Stock</th>
              <th style={thCell}>Cat.</th>
              <th style={thCell}></th>
            </tr>
          </thead>
          <tbody>
            {filas.map((f) => (
              <tr key={f.id} style={trStyle}>
                <td style={tdCell}>
                  {f.fotoSugerida ? 
                    <img alt="Ref" src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/w_100,c_fill/v1/${f.fotoSugerida.publicId}`} style={thumbImg} /> 
                    : <div style={noThumb}><ImageIcon size={20} color="#cbd5e1"/></div>
                  }
                </td>
                <td style={tdCell}>
                  <input style={inputTable} placeholder="Nombre del producto..." value={f.producto} onChange={e => actualizarFila(f.id, 'producto', e.target.value)} />
                </td>
                <td style={tdCell}>
                  <input style={inputTable} type="number" placeholder="0.00" value={f.precioNuevo} onChange={e => actualizarFila(f.id, 'precioNuevo', e.target.value)} />
                </td>
                <td style={tdCell}>
                  <input style={inputTable} type="number" placeholder="0.00" value={f.precioViejo} onChange={e => actualizarFila(f.id, 'precioViejo', e.target.value)} />
                </td>
                <td style={tdCell}>
                  <input style={inputTable} type="number" placeholder="0" value={f.stock} onChange={e => actualizarFila(f.id, 'stock', e.target.value)} />
                </td>
                <td style={tdCell}>
                  <select style={selectStyle} value={f.categoria} onChange={e => actualizarFila(f.id, 'categoria', e.target.value)}>
                    <option value="Almacén">Almacén</option>
                    <option value="Bebidas">Bebidas</option>
                    <option value="Fiambrería">Fiambrería</option>
                    <option value="Limpieza">Limpieza</option>
                  </select>
                </td>
                <td style={tdCell}>
                  <button onClick={() => setFilas(filas.filter(r => r.id !== f.id))} style={btnDel}><Trash size={16}/></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <button onClick={() => setFilas([...filas, filaNueva()])} style={btnAddRow}>
          <Plus size={18}/> Agregar Fila Manual
        </button>
      </div>

      {/* Footer de Fechas y Publicación con estilo Sidebar */}
      <div style={footerStyle}>
        <div style={{display:'flex', gap:'20px', alignItems:'center'}}>
          <div style={inputDateGroup}>
            <label style={labelStyle}><Calendar size={14}/> Desde</label>
            <input type="date" style={dateInput} value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} />
          </div>
          <div style={inputDateGroup}>
            <label style={labelStyle}><Calendar size={14}/> Hasta</label>
            <input type="date" style={dateInput} value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} />
          </div>
        </div>

        <div style={{display:'flex', gap:'15px'}}>
          <button onClick={() => setFilas([filaNueva()])} style={btnLimpiar}>Limpiar Tabla</button>
          <button onClick={publicarOfertas} disabled={cargando} style={btnNuevaSucursalCustom}>
            {cargando ? <Loader2 className="animate-spin"/> : <Sparkles size={18}/>}
            {cargando ? 'Publicando...' : 'Publicar Ofertas'}
          </button>
        </div>
      </div>

      {showGaleria && <ModalGaleria cloudName={CLOUD_NAME} API_URL={API_URL} onClose={() => setShowGaleria(false)} />}
    </div>
  );
};

// --- ESTILOS BASADOS EN TU DASHBOARD ---
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif', background: '#f8fafc', minHeight: '100vh' };
const topNav = { display: 'flex', justifyContent: 'space-between', marginBottom: '30px' };
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const headerSection = { marginBottom: '30px' };
const sidebarTitle = { margin: 0, color: '#1e293b', display: 'flex', alignItems: 'center', gap: '12px', fontSize: '1.8rem' };
const tableWrapper = { background: 'white', borderRadius: '20px', boxShadow: '0 10px 15px rgba(0,0,0,0.02)', border: '1px solid #e2e8f0', overflow: 'hidden' };
const mainTable = { width: '100%', borderCollapse: 'collapse' };
const thRow = { background: '#f8fafc', borderBottom: '1px solid #e2e8f0' };
const thCell = { padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.85rem', fontWeight: 'bold' };
const tdCell = { padding: '12px', borderBottom: '1px solid #f1f5f9' };
const trStyle = { transition: '0.2s' };
const inputTable = { width: '100%', border: 'none', outline: 'none', padding: '10px', borderRadius: '8px', background: 'transparent', fontSize: '0.95rem' };
const selectStyle = { border: '1px solid #e2e8f0', padding: '8px', borderRadius: '8px', outline: 'none', background: '#f8fafc', color: '#475569' };
const thumbImg = { width: '60px', height: '60px', borderRadius: '12px', objectFit: 'cover' };
const noThumb = { width: '60px', height: '60px', background: '#f1f5f9', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const btnAddRow = { width: '100%', padding: '15px', background: 'white', border: 'none', color: '#e67e22', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' };

const footerStyle = { marginTop: '30px', padding: '30px', background: 'white', borderRadius: '24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 -10px 15px rgba(0,0,0,0.01)', border: '1px solid #e2e8f0' };
const inputDateGroup = { display: 'flex', flexDirection: 'column', gap: '5px' };
const labelStyle = { fontSize: '0.75rem', fontWeight: 'bold', color: '#94a3b8', display: 'flex', alignItems: 'center', gap: '4px' };
const dateInput = { padding: '10px', borderRadius: '12px', border: '1px solid #e2e8f0', outline: 'none', background: '#f8fafc' };

// Reutilizando tus clases exactas
const btnOfertaStyle = { background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22', padding: '10px 20px', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold', fontSize: '0.9rem', display: 'flex', alignItems: 'center', gap: '8px' };
const btnNuevaSucursalCustom = { background: '#1e293b', color: 'white', padding: '14px 28px', borderRadius: '16px', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '10px', fontWeight: 'bold' };
const btnLimpiar = { background: '#fef2f2', color: '#ef4444', border: 'none', padding: '14px 20px', borderRadius: '16px', cursor: 'pointer', fontWeight: 'bold' };
const btnDel = { color: '#cbd5e1', background: 'none', border: 'none', cursor: 'pointer' };

// Estilos Modal
const modalOverlay = { position: 'fixed', inset: 0, background: 'rgba(30, 41, 59, 0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1000, backdropFilter: 'blur(4px)' };
const modalContent = { background: 'white', padding: '30px', borderRadius: '24px', boxShadow: '0 25px 50px -12px rgba(0,0,0,0.25)' };
const modalHeader = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const closeBtn = { background: '#f1f5f9', border: 'none', borderRadius: '50%', width: '32px', height: '32px', cursor: 'pointer' };
const dropzoneStyle = { border: '2px dashed #e2e8f0', padding: '40px', borderRadius: '20px', cursor: 'pointer', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '10px', color: '#64748b' };

export default GestionOfertas;
